USE P21;
SET NOCOUNT ON;
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
SELECT result_set='module_hits_container_oe', object_name=OBJECT_SCHEMA_NAME(m.object_id)+'.'+OBJECT_NAME(m.object_id), type_desc=o.type_desc
FROM sys.sql_modules m JOIN sys.objects o ON o.object_id=m.object_id
WHERE m.definition LIKE '%container_receipts%' AND (m.definition LIKE '%oe_line%' OR m.definition LIKE '%oe_hdr%' OR m.definition LIKE '%qty_allocated%' OR m.definition LIKE '%transfer_backorders%' OR m.definition LIKE '%oe_transfer_reserve_flag%')
ORDER BY object_name;
SELECT result_set='module_hits_transfer_allocation', object_name=OBJECT_SCHEMA_NAME(m.object_id)+'.'+OBJECT_NAME(m.object_id), type_desc=o.type_desc
FROM sys.sql_modules m JOIN sys.objects o ON o.object_id=m.object_id
WHERE (m.definition LIKE '%oe_transfer_reserve_flag%' OR m.definition LIKE '%transfer_backorders%' OR m.definition LIKE '%qty_reserved%' OR m.definition LIKE '%qty_allocated%')
  AND (m.definition LIKE '%transfer_line%' OR m.definition LIKE '%transfer_hdr%')
ORDER BY object_name;
SELECT result_set='table_columns_backorder_reserve', table_name=t.name, column_id=CONVERT(varchar(20), c.column_id), column_name=c.name, type_name=ty.name
FROM sys.tables t JOIN sys.schemas s ON s.schema_id=t.schema_id JOIN sys.columns c ON c.object_id=t.object_id JOIN sys.types ty ON ty.user_type_id=c.user_type_id
WHERE s.name='dbo' AND (t.name LIKE '%transfer%backorder%' OR t.name LIKE '%reserve%' OR t.name LIKE '%alloc%')
ORDER BY t.name,c.column_id;
